  4Ôćĺ} from "@chat-exporter/shared";
  5Ôćĺimport { acquireContext, releaseContext } from "./browser-pool.js";
  6Ôćĺimport { MAX_MESSAGE_COUNT, MAX_RAW_HTML_BYTES } from "./constants.js";
  7Ôćĺimport { applyOpenAiStructuring } from "./openai-structuring.js";
  8Ôćĺimport {
  9Ôćĺ  blockNonEssentialResources,
 10Ôćĺ  preparePageScripts,
 11Ôćĺ  truncateMessagesIfNeeded,
 12Ôćĺ  validateRawHtmlSize,
 13Ôćĺ} from "./parser-page-utils.js";
 14Ôćĺimport type { PlatformParserResult, StageCallback } from "./parser-types.js";
 15Ôćĺ
 16Ôćĺ/* ÔöÇÔöÇ Claude share-import constants ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
 17Ôćĺ
 18Ôćĺ/** Timeout for the initial page.goto() navigation. */
 19Ôćĺexport const PAGE_LOAD_TIMEOUT_MS = 30_000;
 20Ôćĺ
 21Ôćĺ/** Timeout for waiting until message elements appear in the DOM. */
 22Ôćĺexport const MESSAGE_WAIT_TIMEOUT_MS = 20_000;
 23Ôćĺ
 24Ôćĺ/** Extra delay after messages appear to let the page stabilize. */
 25Ôćĺexport const PAGE_STABILIZATION_MS = 1_000;
 26Ôćĺ
 27Ôćĺ/* ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
 28Ôćĺ
 29Ôćĺexport async function importClaudeSharePage(
 30Ôćĺ  url: string,
 31Ôćĺ  options?: { onStage?: StageCallback },
 32Ôćĺ): Promise<PlatformParserResult> {
 33Ôćĺ  const context = await acquireContext();
 34Ôćĺ
 35Ôćĺ  try {
 36Ôćĺ    await blockNonEssentialResources(context);
 37Ôćĺ
 38Ôćĺ    const page = await context.newPage();
 39Ôćĺ    await preparePageScripts(page);
 40Ôćĺ
 41Ôćĺ    options?.onStage?.("fetch");
 42Ôćĺ    await page.goto(url, {
 43Ôćĺ      waitUntil: "domcontentloaded",
 44Ôćĺ      timeout: PAGE_LOAD_TIMEOUT_MS,
 45Ôćĺ    });
 46Ôćĺ    await page.waitForFunction(
 47Ôćĺ      () => {
 48Ôćĺ        const root =
 49Ôćĺ          document.querySelector("main, [role='main'], article, body") ??
 50Ôćĺ          document.body;
 51Ôćĺ        return (root.textContent ?? "").trim().length > 32;
 52Ôćĺ      },
 53Ôćĺ      {
 54Ôćĺ        timeout: MESSAGE_WAIT_TIMEOUT_MS,
 55Ôćĺ      },
 56Ôćĺ    );
 57Ôćĺ    await page.waitForTimeout(PAGE_STABILIZATION_MS);
 58Ôćĺ
 59Ôćĺ    options?.onStage?.("extract");
 60Ôćĺ    const extracted = await page.evaluate(() => {
 61Ôćĺ      const { normalizeWhitespace, elementToBlocks } = globalThis.__domKit;
 62Ôćĺ
 63Ôćĺ      function normalizeTitle(rawTitle: string) {
 64Ôćĺ        return (
 65Ôćĺ          rawTitle.replace(/^Claude\s*[-ÔÇôÔÇö|]\s*/i, "").trim() || "Untitled Chat"
 66Ôćĺ        );
 67Ôćĺ      }
 68Ôćĺ
 69Ôćĺ      const warnings: string[] = [];
 70Ôćĺ
 71Ôćĺ      // Strategy 1: Look for data-testid based turn containers
 72Ôćĺ      // Claude share pages typically use [data-testid] patterns
 73Ôćĺ      const turnSelectors = [
 74Ôćĺ        '[data-testid*="conversation-turn"]',
 75Ôćĺ        '[data-testid*="chat-turn"]',
 76Ôćĺ        '[data-testid*="message"]',
 77Ôćĺ        ".conversation-turn",
 78Ôćĺ        ".chat-message",
 79Ôćĺ      ];
 80Ôćĺ
 81Ôćĺ      let turnElements: Element[] = [];
 82Ôćĺ      for (const selector of turnSelectors) {
 83Ôćĺ        turnElements = Array.from(document.querySelectorAll(selector));
 84Ôćĺ        if (turnElements.length >= 2) break;
 85Ôćĺ      }
 86Ôćĺ
 87Ôćĺ      // Strategy 2: If no explicit turns found, look for role-based containers
 88Ôćĺ      if (turnElements.length < 2) {
 89Ôćĺ        const allMessages = Array.from(
 90Ôćĺ          document.querySelectorAll(
 91Ôćĺ            '[class*="human"], [class*="user"], [data-role="human"], [data-role="user"], [class*="assistant"], [data-role="assistant"]',
 92Ôćĺ          ),
 93Ôćĺ        );
 94Ôćĺ        if (allMessages.length >= 2) {
 95Ôćĺ          turnElements = allMessages;
 96Ôćĺ        }
 97Ôćĺ      }
 98Ôćĺ
 99Ôćĺ      // Strategy 3: Content-based heuristic
100Ôćĺ      if (turnElements.length < 2) {
101Ôćĺ        const mainContent = document.querySelector(
102Ôćĺ          'main, [role="main"], .conversation, .chat-content',
103Ôćĺ        );
104Ôćĺ        if (mainContent) {
105Ôćĺ          const candidates = Array.from(mainContent.children).filter(
106Ôćĺ            (child) => {
107Ôćĺ              const text = (child.textContent ?? "").trim();
108Ôćĺ              return text.length > 5 && child.children.length > 0;
109Ôćĺ            },
110Ôćĺ          );
111Ôćĺ          if (candidates.length >= 2) {
112Ôćĺ            turnElements = candidates;
113Ôćĺ            warnings.push(
114Ôćĺ              "Used content heuristic to identify messages ÔÇö extraction quality may vary.",
115Ôćĺ            );
116Ôćĺ          }
117Ôćĺ        }
118Ôćĺ      }
119Ôćĺ
120Ôćĺ      if (turnElements.length === 0) {
121Ôćĺ        return {
122Ôćĺ          title: normalizeTitle(document.title),
123Ôćĺ          messages: [],
124Ôćĺ          warnings: ["No conversation turns found on Claude share page."],
125Ôćĺ        };
126Ôćĺ      }
127Ôćĺ
128Ôćĺ      let fallbackCount = 0;
129Ôćĺ      const messages = turnElements
130Ôćĺ        .map((turn, index) => {
131Ôćĺ          // Determine role
132Ôćĺ          const testId = turn.getAttribute("data-testid") ?? "";
133Ôćĺ          const dataRole = turn.getAttribute("data-role") ?? "";
134Ôćĺ          const className = (turn.className ?? "").toLowerCase();
135Ôćĺ
136Ôćĺ          let role = "unknown";
137Ôćĺ          if (
138Ôćĺ            dataRole === "human" ||
139Ôćĺ            dataRole === "user" ||
140Ôćĺ            className.includes("human") ||
141Ôćĺ            className.includes("user") ||
142Ôćĺ            testId.includes("user") ||
143Ôćĺ            testId.includes("human")
144Ôćĺ          ) {
145Ôćĺ            role = "user";
146Ôćĺ          } else if (
147Ôćĺ            dataRole === "assistant" ||
148Ôćĺ            className.includes("assistant") ||
149Ôćĺ            testId.includes("assistant")
150Ôćĺ          ) {
151Ôćĺ            role = "assistant";
152Ôćĺ          } else {
153Ôćĺ            // Alternating pattern: even indices = user, odd = assistant
154Ôćĺ            role = index % 2 === 0 ? "user" : "assistant";
155Ôćĺ            if (turnElements.length > 1) {
156Ôćĺ              warnings.push(
157Ôćĺ                `Inferred role for message ${index + 1} as "${role}" from position.`,
158Ôćĺ              );
159Ôćĺ            }
160Ôćĺ          }
161Ôćĺ
162Ôćĺ          const messageId =
163Ôćĺ            turn.getAttribute("data-message-id") ??
164Ôćĺ            turn.getAttribute("data-testid") ??
165Ôćĺ            crypto.randomUUID();
166Ôćĺ
167Ôćĺ          // Extract blocks
168Ôćĺ          const contentRoot =
169Ôćĺ            turn.querySelector(
170Ôćĺ              '.markdown, .prose, .message-content, [class*="content"]',
171Ôćĺ            ) ?? turn;
172Ôćĺ          const blocks = Array.from(contentRoot.childNodes).flatMap(
173Ôćĺ            (childNode) => {
174Ôćĺ              if (childNode.nodeType === Node.TEXT_NODE) {
175Ôćĺ                const text = normalizeWhitespace(childNode.textContent ?? "");
176Ôćĺ                return text ? [{ type: "paragraph" as const, text }] : [];
177Ôćĺ              }
178Ôćĺ              if (childNode.nodeType !== Node.ELEMENT_NODE) return [];
179Ôćĺ              return elementToBlocks(childNode as Element);
180Ôćĺ            },
181Ôćĺ          );
182Ôćĺ
183Ôćĺ          const rawText = normalizeWhitespace(
184Ôćĺ            (turn as HTMLElement).innerText ?? turn.textContent ?? "",
185Ôćĺ          );
186Ôćĺ
187Ôćĺ          if (blocks.length === 0 && rawText) {
188Ôćĺ            fallbackCount++;
189Ôćĺ            return {
190Ôćĺ              id: messageId,
191Ôćĺ              role,
192Ôćĺ              rawText,
193Ôćĺ              rawHtml: (turn as HTMLElement).innerHTML,
194Ôćĺ              blocks: [{ type: "paragraph" as const, text: rawText }],
195Ôćĺ              parser: {
196Ôćĺ                source: "claude-fallback",
197Ôćĺ                blockCount: 1,
198Ôćĺ                usedFallback: true,
199Ôćĺ                strategy: "fallback" as const,
200Ôćĺ              },
201Ôćĺ            };
202Ôćĺ          }
203Ôćĺ
204Ôćĺ          if (blocks.length === 0) return null;
205Ôćĺ
206Ôćĺ          return {
207Ôćĺ            id: messageId,
208Ôćĺ            role,
209Ôćĺ            rawText,
210Ôćĺ            rawHtml: (turn as HTMLElement).innerHTML,
211Ôćĺ            blocks,
212Ôćĺ            parser: {
213Ôćĺ              source: "claude-structured",
214Ôćĺ              blockCount: blocks.length,
215Ôćĺ              usedFallback: false,
216Ôćĺ              strategy: "deterministic" as const,
217Ôćĺ            },
218Ôćĺ          };
219Ôćĺ        })
220Ôćĺ        .filter(Boolean);
221Ôćĺ
222Ôćĺ      if (fallbackCount > 0) {
223Ôćĺ        warnings.push(
224Ôćĺ          `${fallbackCount} message(s) fell back to plain paragraph.`,
225Ôćĺ        );
226Ôćĺ      }
227Ôćĺ
228Ôćĺ      return { title: normalizeTitle(document.title), messages, warnings };
229Ôćĺ    });
230Ôćĺ
231Ôćĺ    options?.onStage?.("normalize");
232Ôćĺ    const normalizedPayload = normalizedSnapshotPayloadSchema.parse(extracted);
233Ôćĺ    truncateMessagesIfNeeded(normalizedPayload, MAX_MESSAGE_COUNT);
234Ôćĺ
235Ôćĺ    options?.onStage?.("structure");
236Ôćĺ    const structured = await applyOpenAiStructuring(normalizedPayload.messages);
237Ôćĺ    const finalPayload = normalizedSnapshotPayloadSchema.parse({
238Ôćĺ      ...normalizedPayload,
239Ôćĺ      messages: structured.messages,
240Ôćĺ      warnings: [...normalizedPayload.warnings, ...structured.warnings],
241Ôćĺ      structuring: structured.structuring,
242Ôćĺ    });
243Ôćĺ
244Ôćĺ    const rawHtml = await page.content();
245Ôćĺ    const rawHtmlBytes = validateRawHtmlSize(rawHtml, MAX_RAW_HTML_BYTES);
246Ôćĺ    const fetchedAt = new Date().toISOString();
247Ôćĺ
248Ôćĺ    const conversation = conversationSchema.parse({
249Ôćĺ      id: crypto.randomUUID(),
250Ôćĺ      title: finalPayload.title,
251Ôćĺ      source: {
252Ôćĺ        url,
253Ôćĺ        platform: "claude",
254Ôćĺ      },
255Ôćĺ      messages: finalPayload.messages,
256Ôćĺ    });
257Ôćĺ
258Ôćĺ    return {
259Ôćĺ      conversation,
260Ôćĺ      warnings: finalPayload.warnings,
261Ôćĺ      snapshot: {
262Ôćĺ        finalUrl: page.url(),
263Ôćĺ        fetchedAt,
264Ôćĺ        pageTitle: finalPayload.title,
265Ôćĺ        rawHtml,
266Ôćĺ        normalizedPayload: finalPayload,
267Ôćĺ        fetchMetadata: {
268Ôćĺ          articleCount: normalizedPayload.messages.length,
269Ôćĺ          messageCount: conversation.messages.length,
270Ôćĺ          rawHtmlBytes,
271Ôćĺ        },
272Ôćĺ      },
273Ôćĺ    };
274Ôćĺ  } finally {
275Ôćĺ    await releaseContext(context);
276Ôćĺ  }
277Ôćĺ}
