 26Ôćĺexport const PAGE_STABILIZATION_MS = 1_200;
 27Ôćĺ
 28Ôćĺ/* ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
 29Ôćĺ
 30Ôćĺexport async function importDeepSeekSharePage(
 31Ôćĺ  url: string,
 32Ôćĺ  options?: {
 33Ôćĺ    onStage?: StageCallback;
 34Ôćĺ  },
 35Ôćĺ): Promise<PlatformParserResult> {
 36Ôćĺ  const context = await acquireContext();
 37Ôćĺ
 38Ôćĺ  try {
 39Ôćĺ    await blockNonEssentialResources(context);
 40Ôćĺ
 41Ôćĺ    const page = await context.newPage();
 42Ôćĺ    await preparePageScripts(page);
 43Ôćĺ
 44Ôćĺ    options?.onStage?.("fetch");
 45Ôćĺ    await page.goto(url, {
 46Ôćĺ      waitUntil: "domcontentloaded",
 47Ôćĺ      timeout: PAGE_LOAD_TIMEOUT_MS,
 48Ôćĺ    });
 49Ôćĺ
 50Ôćĺ    // Wait for meaningful content to appear in the DOM
 51Ôćĺ    await page
 52Ôćĺ      .waitForFunction(
 53Ôćĺ        () => {
 54Ôćĺ          // Strategy 1: DeepSeek-specific selectors
 55Ôćĺ          const specificSelectors = [
 56Ôćĺ            "[data-testid*='message']",
 57Ôćĺ            "[data-testid*='chat']",
 58Ôćĺ            ".ds-message",
 59Ôćĺ            ".chat-message",
 60Ôćĺ            "[class*='message']",
 61Ôćĺ            "[class*='Message']",
 62Ôćĺ            "[role='article']",
 63Ôćĺ          ];
 64Ôćĺ
 65Ôćĺ          for (const selector of specificSelectors) {
 66Ôćĺ            if (document.querySelectorAll(selector).length > 0) {
 67Ôćĺ              return true;
 68Ôćĺ            }
 69Ôćĺ          }
 70Ôćĺ
 71Ôćĺ          // Strategy 2: Look for substantial text content in main area
 72Ôćĺ          const root =
 73Ôćĺ            document.querySelector("main, [role='main'], article, #app") ??
 74Ôćĺ            document.body;
 75Ôćĺ          return (root.textContent ?? "").trim().length > 100;
 76Ôćĺ        },
 77Ôćĺ        { timeout: MESSAGE_WAIT_TIMEOUT_MS },
 78Ôćĺ      )
 79Ôćĺ      .catch(() => undefined);
 80Ôćĺ
 81Ôćĺ    await page.waitForTimeout(PAGE_STABILIZATION_MS);
 82Ôćĺ
 83Ôćĺ    options?.onStage?.("extract");
 84Ôćĺ    const extracted = await page.evaluate(() => {
 85Ôćĺ      const { normalizeWhitespace, elementToBlocks } = globalThis.__domKit;
 86Ôćĺ
 87Ôćĺ      function normalizeTitle(rawTitle: string) {
 88Ôćĺ        const title = rawTitle
 89Ôćĺ          .replace(/\s*[-|]\s*DeepSeek.*$/i, "")
 90Ôćĺ          .replace(/^DeepSeek\s*[-|:]\s*/i, "")
 91Ôćĺ          .replace(/^shared\s+/i, "")
 92Ôćĺ          .trim();
 93Ôćĺ
 94Ôćĺ        return title || "Untitled Chat";
 95Ôćĺ      }
 96Ôćĺ
 97Ôćĺ      function isExcluded(element: Element) {
 98Ôćĺ        return Boolean(
 99Ôćĺ          element.closest(
100Ôćĺ            "nav,header,footer,aside,form,dialog,[role='navigation'],[aria-hidden='true']",
101Ôćĺ          ),
102Ôćĺ        );
103Ôćĺ      }
104Ôćĺ
105Ôćĺ      function isVisible(element: Element) {
106Ôćĺ        const computed = globalThis.getComputedStyle(element as HTMLElement);
107Ôćĺ
108Ôćĺ        if (
109Ôćĺ          computed.display === "none" ||
110Ôćĺ          computed.visibility === "hidden" ||
111Ôćĺ          computed.opacity === "0"
112Ôćĺ        ) {
113Ôćĺ          return false;
114Ôćĺ        }
115Ôćĺ
116Ôćĺ        const rect = (element as HTMLElement).getBoundingClientRect();
117Ôćĺ        return rect.width > 0 && rect.height > 0;
118Ôćĺ      }
119Ôćĺ
120Ôćĺ      function contentRootFor(element: Element) {
121Ôćĺ        return (
122Ôćĺ          element.querySelector(
123Ôćĺ            ".markdown, [data-testid*='markdown'], [class*='markdown'], [data-testid*='response-content'], [data-testid*='message-content'], [data-message-content]",
124Ôćĺ          ) ?? element
125Ôćĺ        );
126Ôćĺ      }
127Ôćĺ
128Ôćĺ      function extractBlocksFromElement(element: Element) {
129Ôćĺ        return Array.from(element.childNodes).flatMap((childNode) => {
130Ôćĺ          if (childNode.nodeType === Node.TEXT_NODE) {
131Ôćĺ            const text = normalizeWhitespace(childNode.textContent ?? "");
132Ôćĺ            return text ? [{ type: "paragraph" as const, text }] : [];
133Ôćĺ          }
134Ôćĺ
135Ôćĺ          if (childNode.nodeType !== Node.ELEMENT_NODE) {
136Ôćĺ            return [];
137Ôćĺ          }
138Ôćĺ
139Ôćĺ          return elementToBlocks(childNode as Element);
140Ôćĺ        });
141Ôćĺ      }
142Ôćĺ
143Ôćĺ      /**
144Ôćĺ       * Extract thinking/reasoning blocks from DeepSeek-R1 responses.
145Ôćĺ       * These are rendered as collapsible or specially marked sections
146Ôćĺ       * showing the model's chain-of-thought reasoning.
147Ôćĺ       */
148Ôćĺ      function extractThinkingBlocks(
149Ôćĺ        element: Element,
150Ôćĺ      ): Array<Record<string, unknown>> {
151Ôćĺ        const thinkingSelectors = [
152Ôćĺ          "[class*='think']",
153Ôćĺ          "[class*='Think']",
154Ôćĺ          "[class*='reason']",
155Ôćĺ          "[class*='Reason']",
156Ôćĺ          "[data-testid*='think']",
157Ôćĺ          "[data-testid*='reason']",
158Ôćĺ          ".ds-think",
159Ôćĺ          ".ds-reasoning",
160Ôćĺ          "details.thinking",
161Ôćĺ          "[class*='chain-of-thought']",
162Ôćĺ        ];
163Ôćĺ
164Ôćĺ        const blocks: Array<Record<string, unknown>> = [];
165Ôćĺ
166Ôćĺ        for (const selector of thinkingSelectors) {
167Ôćĺ          const thinkingElements = element.querySelectorAll(selector);
168Ôćĺ          for (const thinkingEl of thinkingElements) {
169Ôćĺ            const text = normalizeWhitespace(
170Ôćĺ              (thinkingEl as HTMLElement).innerText,
171Ôćĺ            );
172Ôćĺ            if (text) {
173Ôćĺ              blocks.push({
174Ôćĺ                type: "quote" as const,
175Ôćĺ                text: `[Thinking] ${text}`,
176Ôćĺ              });
177Ôćĺ            }
178Ôćĺ          }
179Ôćĺ        }
180Ôćĺ
181Ôćĺ        return blocks;
182Ôćĺ      }
183Ôćĺ
184Ôćĺ      type MessageEntry = {
185Ôćĺ        id: string;
186Ôćĺ        role: "user" | "assistant";
187Ôćĺ        rawText: string;
188Ôćĺ        rawHtml: string;
189Ôćĺ        blocks: Array<Record<string, unknown>>;
190Ôćĺ        parser: {
191Ôćĺ          source: string;
192Ôćĺ          blockCount: number;
