273Ôćĺ          messages: [] as Array<{
274Ôćĺ            id: string;
275Ôćĺ            role: "user" | "assistant" | "unknown";
276Ôćĺ            rawText: string;
277Ôćĺ            rawHtml: string;
278Ôćĺ            blocks: Array<Record<string, unknown>>;
279Ôćĺ            parser: {
