294Ôćĺ      const messages: Array<{
295Ôćĺ        id: string;
296Ôćĺ        role: "user" | "assistant" | "unknown";
297Ôćĺ        rawText: string;
298Ôćĺ        rawHtml: string;
299Ôćĺ        blocks: Array<Record<string, unknown>>;
300Ôćĺ        parser: {
301Ôćĺ          source: string;
302Ôćĺ          blockCount: number;
303Ôćĺ          usedFallback: boolean;
304Ôćĺ          strategy: "deterministic" | "fallback";
