225Ôćĺ            (child) =>
226Ôćĺ              isVisible(child) &&
227Ôćĺ              !isExcluded(child) &&
228Ôćĺ              normalizeWhitespace((child as HTMLElement).innerText).length > 10,
229Ôćĺ          );
