236Ôćĺ        for (const candidate of candidates.slice(0, 100)) {
237Ôćĺ          const children = Array.from(candidate.children).filter((child) => {
238Ôćĺ            if (!isVisible(child) || isExcluded(child)) return false;
239Ôćĺ            const text = normalizeWhitespace((child as HTMLElement).innerText);
240Ôćĺ            return text.length > 10;
