269Ôćĺ          messages: [] as Array<{
270Ôćĺ            id: string;
271Ôćĺ            role: "user" | "assistant" | "unknown";
272Ôćĺ            rawText: string;
273Ôćĺ            rawHtml: string;
274Ôćĺ            blocks: Array<Record<string, unknown>>;
275Ôćĺ            parser: {
