291Ôćĺ        id: string;
292Ôćĺ        role: "user" | "assistant" | "unknown";
293Ôćĺ        rawText: string;
294Ôćĺ        rawHtml: string;
295Ôćĺ        blocks: Array<Record<string, unknown>>;
296Ôćĺ        parser: {
297Ôćĺ          source: string;
298Ôćĺ          blockCount: number;
299Ôćĺ          usedFallback: boolean;
300Ôćĺ          strategy: "deterministic" | "fallback";
