215Ôćĺ      if (turnElements.length < 2) {
216Ôćĺ        const mainContent =
217Ôćĺ          document.querySelector("main") ??
218Ôćĺ          document.querySelector("[role='main']") ??
219Ôćĺ          document.querySelector("article") ??
220Ôćĺ          document.body;
