160Ôćĺ      if (
161Ôćĺ        !codeLanguageLabels.has(firstLine) &&
162Ôćĺ        firstLine !== "kopieren" &&
163Ôćĺ        firstLine !== "copy"
164Ôćĺ      ) {
165Ôćĺ        break;
166Ôćĺ      }
167Ôćĺ      lines.shift();
168Ôćĺ    }
169Ôćĺ
170Ôćĺ    return lines.join("\\n").trim();
171Ôćĺ  }
172Ôćĺ
173Ôćĺ  function extractTable(tableElement) {
174Ôćĺ    var headerRows = Array.from(tableElement.querySelectorAll("thead tr"));
175Ôćĺ    var bodyRows = Array.from(tableElement.querySelectorAll("tbody tr"));
176Ôćĺ    var fallbackRows = Array.from(tableElement.querySelectorAll("tr"));
177Ôćĺ    var firstHeaderRow = headerRows[0];
178Ôćĺ
179Ôćĺ    var headers = firstHeaderRow
180Ôćĺ      ? Array.from(firstHeaderRow.querySelectorAll("th,td")).map(function(cell) {
181Ôćĺ          return inlineFromElement(cell);
182Ôćĺ        })
183Ôćĺ      : [];
184Ôćĺ
185Ôćĺ    var rowSource =
186Ôćĺ      bodyRows.length > 0
187Ôćĺ        ? bodyRows
188Ôćĺ        : fallbackRows.slice(headers.length > 0 ? 1 : 0);
189Ôćĺ    var rows = rowSource
190Ôćĺ      .map(function(row) {
191Ôćĺ        return Array.from(row.querySelectorAll("th,td")).map(function(cell) {
192Ôćĺ          return inlineFromElement(cell);
193Ôćĺ        });
194Ôćĺ      })
195Ôćĺ      .filter(function(row) { return row.some(Boolean); });
196Ôćĺ
197Ôćĺ    if (headers.length === 0 && rows.length === 0) {
198Ôćĺ      return null;
199Ôćĺ    }
200Ôćĺ
201Ôćĺ    return {
202Ôćĺ      type: "table",
203Ôćĺ      headers: headers,
204Ôćĺ      rows: rows
205Ôćĺ    };
206Ôćĺ  }
207Ôćĺ
208Ôćĺ  function elementToBlocks(element) {
209Ôćĺ    var tagName = element.tagName.toUpperCase();
210Ôćĺ
211Ôćĺ    if (tagName === "P") {
212Ôćĺ      var text = inlineFromElement(element);
213Ôćĺ      return text ? [{ type: "paragraph", text: text }] : [];
214Ôćĺ    }
215Ôćĺ
216Ôćĺ    if (/^H[1-6]$/.test(tagName)) {
217Ôćĺ      var text = inlineFromElement(element);
218Ôćĺ      var level = Number(tagName.slice(1));
219Ôćĺ      return text ? [{ type: "heading", level: level, text: text }] : [];
220Ôćĺ    }
221Ôćĺ
222Ôćĺ    if (tagName === "UL" || tagName === "OL") {
223Ôćĺ      var items = extractListItems(element);
224Ôćĺ      return items.length > 0
225Ôćĺ        ? [{ type: "list", ordered: tagName === "OL", items: items }]
226Ôćĺ        : [];
227Ôćĺ    }
228Ôćĺ
229Ôćĺ    if (tagName === "PRE") {
230Ôćĺ      var text = extractCodeText(element);
231Ôćĺ      return text
232Ôćĺ        ? [{ type: "code", language: detectCodeLanguage(element), text: text }]
233Ôćĺ        : [];
234Ôćĺ    }
235Ôćĺ
236Ôćĺ    if (tagName === "BLOCKQUOTE") {
237Ôćĺ      var text = inlineFromElement(element);
238Ôćĺ      return text ? [{ type: "quote", text: text }] : [];
239Ôćĺ    }
240Ôćĺ
241Ôćĺ    if (tagName === "TABLE") {
242Ôćĺ      var table = extractTable(element);
243Ôćĺ      return table ? [table] : [];
244Ôćĺ    }
245Ôćĺ
246Ôćĺ    if (tagName === "HR") {
247Ôćĺ      return [];
248Ôćĺ    }
249Ôćĺ
250Ôćĺ    if (wrapperTags.has(tagName)) {
251Ôćĺ      var childBlocks = Array.from(element.childNodes).reduce(function(acc, childNode) {
252Ôćĺ        if (childNode.nodeType === Node.TEXT_NODE) {
253Ôćĺ          var text = normalizeWhitespace(childNode.textContent != null ? childNode.textContent : "");
254Ôćĺ          if (text) acc.push({ type: "paragraph", text: text });
255Ôćĺ          return acc;
256Ôćĺ        }
257Ôćĺ
258Ôćĺ        if (childNode.nodeType !== Node.ELEMENT_NODE) {
259Ôćĺ          return acc;
260Ôćĺ        }
261Ôćĺ
262Ôćĺ        var blocks = elementToBlocks(childNode);
263Ôćĺ        for (var b = 0; b < blocks.length; b++) acc.push(blocks[b]);
264Ôćĺ        return acc;
265Ôćĺ      }, []);
266Ôćĺ
267Ôćĺ      if (childBlocks.length > 0) {
268Ôćĺ        return childBlocks;
269Ôćĺ      }
270Ôćĺ    }
271Ôćĺ
272Ôćĺ    var hasBlockChildren = Array.from(element.children).some(function(child) {
273Ôćĺ      return blockTags.has(child.tagName);
274Ôćĺ    });
275Ôćĺ
276Ôćĺ    if (hasBlockChildren) {
277Ôćĺ      return Array.from(element.children).reduce(function(acc, child) {
278Ôćĺ        var blocks = elementToBlocks(child);
279Ôćĺ        for (var b = 0; b < blocks.length; b++) acc.push(blocks[b]);
280Ôćĺ        return acc;
281Ôćĺ      }, []);
282Ôćĺ    }
283Ôćĺ
284Ôćĺ    var text = inlineFromElement(element);
285Ôćĺ    return text ? [{ type: "paragraph", text: text }] : [];
286Ôćĺ  }
287Ôćĺ
288Ôćĺ  globalThis.__domKit = {
289Ôćĺ    wrapperTags: wrapperTags,
290Ôćĺ    blockTags: blockTags,
291Ôćĺ    codeLanguageLabels: codeLanguageLabels,
292Ôćĺ    normalizeWhitespace: normalizeWhitespace,
293Ôćĺ    inlineText: inlineText,
294Ôćĺ    inlineFromElement: inlineFromElement,
295Ôćĺ    extractListItems: extractListItems,
296Ôćĺ    detectCodeLanguage: detectCodeLanguage,
297Ôćĺ    extractCodeText: extractCodeText,
298Ôćĺ    extractTable: extractTable,
299Ôćĺ    elementToBlocks: elementToBlocks
300Ôćĺ  };
301Ôćĺ})();`;
