303Ôćĺ/** TypeScript interface describing what __domKit provides in browser context. */
304Ôćĺexport interface DomKit {
305Ôćĺ  wrapperTags: Set<string>;
306Ôćĺ  blockTags: Set<string>;
307Ôćĺ  codeLanguageLabels: Set<string>;
308Ôćĺ  normalizeWhitespace: (value: string | null | undefined) => string;
309Ôćĺ  inlineText: (node: Node) => string;
310Ôćĺ  inlineFromElement: (element: Element) => string;
311Ôćĺ  extractListItems: (listElement: Element, depth?: number) => string[];
312Ôćĺ  detectCodeLanguage: (preElement: HTMLElement) => string;
313Ôćĺ  extractCodeText: (preElement: HTMLElement) => string;
314Ôćĺ  extractTable: (
