 5Ôćĺ/** Block image, media, and font requests to reduce bandwidth. */
 6Ôćĺexport async function blockNonEssentialResources(
 7Ôćĺ  context: BrowserContext,
 8Ôćĺ): Promise<void> {
 9Ôćĺ  await context.route("**/*", (route) => {
10Ôćĺ    const resourceType = route.request().resourceType();
11Ôćĺ    if (
12Ôćĺ      resourceType === "image" ||
13Ôćĺ      resourceType === "media" ||
14Ôćĺ      resourceType === "font"
15Ôćĺ    ) {
16Ôćĺ      return route.abort();
17Ôćĺ    }
18Ôćĺ    return route.continue();
19Ôćĺ  });
20Ôćĺ}
