45Ôćĺ/** Validate raw HTML size against limit. Returns byte size. Throws if exceeded. */
46Ôćĺexport function validateRawHtmlSize(rawHtml: string, maxBytes: number): number {
47Ôćĺ  const rawHtmlBytes = Buffer.byteLength(rawHtml, "utf8");
48Ôćĺ  if (rawHtmlBytes > maxBytes) {
49Ôćĺ    const sizeMb = (rawHtmlBytes / (1024 * 1024)).toFixed(1);
50Ôćĺ    const limitMb = (maxBytes / (1024 * 1024)).toFixed(1);
51Ôćĺ    throw new Error(
52Ôćĺ      `HTML-Gr├Â├če ├╝berschritten: ${sizeMb} MB (Limit: ${limitMb} MB).`,
53Ôćĺ    );
54Ôćĺ  }
55Ôćĺ  return rawHtmlBytes;
56Ôćĺ}
