129Ôćĺexport function listImportSummaries(
130Ôćĺ  params?: Partial<ImportListRequest>,
131Ôćĺ): ImportSummary[] {
132Ôćĺ  const sortBy = params?.sortBy ?? "createdAt";
133Ôćĺ  const sortOrder = params?.sortOrder ?? "desc";
134Ôćĺ
135Ôćĺ  const columnMap = {
136Ôćĺ    createdAt: imports.createdAt,
137Ôćĺ    updatedAt: imports.updatedAt,
138Ôćĺ    sourcePlatform: imports.sourcePlatform,
139Ôćĺ    status: imports.status,
140Ôćĺ  } as const;
141Ôćĺ
142Ôćĺ  const orderColumn = columnMap[sortBy];
143Ôćĺ  const orderFn = sortOrder === "asc" ? asc : desc;
144Ôćĺ
145Ôćĺ  let query = db
146Ôćĺ    .select({
147Ôćĺ      id: imports.id,
148Ôćĺ      sourceUrl: imports.sourceUrl,
149Ôćĺ      sourcePlatform: imports.sourcePlatform,
150Ôćĺ      mode: imports.mode,
151Ôćĺ      importMethod: imports.importMethod,
152Ôćĺ      status: imports.status,
153Ôćĺ      currentStage: imports.currentStage,
154Ôćĺ      createdAt: imports.createdAt,
155Ôćĺ      updatedAt: imports.updatedAt,
156Ôćĺ      warningsJson: imports.warningsJson,
157Ôćĺ      error: imports.error,
158Ôćĺ      summaryJson: imports.summaryJson,
159Ôćĺ      pageTitle: importSnapshots.pageTitle,
160Ôćĺ    })
161Ôćĺ    .from(imports)
162Ôćĺ    .leftJoin(importSnapshots, eq(imports.id, importSnapshots.importId))
163Ôćĺ    .orderBy(orderFn(orderColumn))
164Ôćĺ    .$dynamic();
165Ôćĺ
166Ôćĺ  const conditions = [];
167Ôćĺ
168Ôćĺ  if (params?.status) {
169Ôćĺ    conditions.push(eq(imports.status, params.status));
170Ôćĺ  }
171Ôćĺ
172Ôćĺ  if (params?.platform) {
173Ôćĺ    conditions.push(eq(imports.sourcePlatform, params.platform));
174Ôćĺ  }
175Ôćĺ
176Ôćĺ  if (params?.search) {
177Ôćĺ    const pattern = `%${params.search}%`;
178Ôćĺ    conditions.push(
179Ôćĺ      or(
180Ôćĺ        like(imports.sourceUrl, pattern),
181Ôćĺ        like(importSnapshots.pageTitle, pattern),
182Ôćĺ      ),
183Ôćĺ    );
184Ôćĺ  }
185Ôćĺ
186Ôćĺ  if (conditions.length > 0) {
187Ôćĺ    query = query.where(and(...conditions));
188Ôćĺ  }
189Ôćĺ
190Ôćĺ  return query.all().flatMap((row) => {
191Ôćĺ    const parsed = importSummarySchema.safeParse({
192Ôćĺ      id: row.id,
193Ôćĺ      sourceUrl: row.sourceUrl,
194Ôćĺ      sourcePlatform: row.sourcePlatform,
195Ôćĺ      mode: row.mode,
196Ôćĺ      importMethod: row.importMethod,
197Ôćĺ      status: row.status,
198Ôćĺ      currentStage: row.currentStage,
199Ôćĺ      createdAt: row.createdAt,
200Ôćĺ      updatedAt: row.updatedAt,
201Ôćĺ      warnings: parseJson<string[]>(row.warningsJson) ?? [],
202Ôćĺ      error: row.error ?? undefined,
203Ôćĺ      summary: parseJson<ImportJob["summary"]>(row.summaryJson),
204Ôćĺ      pageTitle: row.pageTitle ?? undefined,
205Ôćĺ    });
206Ôćĺ    return parsed.success ? [parsed.data] : [];
207Ôćĺ  });
208Ôćĺ}
