 47Ôćĺ    return "gemini";
 48Ôćĺ  if (lower.includes("grok")) return "grok";
 49Ôćĺ  if (lower.includes("deepseek")) return "deepseek";
 50Ôćĺ  if (lower.includes("perplexity")) return "perplexity";
 51Ôćĺ  if (lower.includes("mistral") || lower.includes("lechat")) return "lechat";
 52Ôćĺ
 53Ôćĺ  return "unknown";
 54Ôćĺ}
