 56Ôćĺ// ---------------------------------------------------------------------------
 57Ôćĺ// HTML path
 58Ôćĺ// ---------------------------------------------------------------------------
 59Ôćĺ
 60Ôćĺfunction importFromClipboardHtml(
 61Ôćĺ  html: string,
 62Ôćĺ  warnings: string[],
 63Ôćĺ): ClipboardImportResult {
 64Ôćĺ  const platform = detectPlatformFromHtml(html);
 65Ôćĺ
 66Ôćĺ  if (platform === "unknown") {
 67Ôćĺ    warnings.push("Could not detect platform from clipboard HTML");
 68Ôćĺ  }
 69Ôćĺ
 70Ôćĺ  const dom = new JSDOM(html, { runScripts: "outside-only" });
 71Ôćĺ  const { window } = dom;
 72Ôćĺ
 73Ôćĺ  // Inject DOM kit helpers via eval ÔÇö "outside-only" prevents user-supplied
 74Ôćĺ  // scripts from executing while allowing programmatic injection.
 75Ôćĺ  window.eval(DOM_KIT_SCRIPT);
 76Ôćĺ
 77Ôćĺ  // biome-ignore lint/suspicious/noExplicitAny: JSDOM global access requires dynamic typing
 78Ôćĺ  const domKit = (window as any).__domKit as
 79Ôćĺ    | {
 80Ôćĺ        elementToBlocks: (el: Element) => Array<Record<string, unknown>>;
 81Ôćĺ      }
 82Ôćĺ    | undefined;
 83Ôćĺ
 84Ôćĺ  if (!domKit) {
 85Ôćĺ    warnings.push("DOM kit injection failed, falling back to basic extraction");
 86Ôćĺ    const text = window.document.body?.textContent?.trim() ?? "";
 87Ôćĺ    window.close();
 88Ôćĺ    return createSingleMessageResult(text, platform, warnings);
 89Ôćĺ  }
 90Ôćĺ
 91Ôćĺ  const messages = extractMessagesFromDom(
 92Ôćĺ    window.document,
 93Ôćĺ    domKit,
 94Ôćĺ    platform,
 95Ôćĺ    warnings,
 96Ôćĺ  );
 97Ôćĺ
 98Ôćĺ  const title = extractTitleFromDom(window.document, platform) || "Pasted Chat";
 99Ôćĺ
100Ôćĺ  window.close();
101Ôćĺ
102Ôćĺ  if (messages.length === 0) {
103Ôćĺ    warnings.push("No messages found in clipboard HTML");
104Ôćĺ    const text = html
105Ôćĺ      .replace(/<[^>]*>/g, " ")
106Ôćĺ      .replace(/\s+/g, " ")
107Ôćĺ      .trim();
108Ôćĺ    return createSingleMessageResult(text, platform, warnings);
109Ôćĺ  }
110Ôćĺ
111Ôćĺ  const conversation = conversationSchema.parse({
112Ôćĺ    id: crypto.randomUUID(),
113Ôćĺ    title,
114Ôćĺ    source: { url: "clipboard://paste", platform },
115Ôćĺ    messages,
116Ôćĺ  });
117Ôćĺ
118Ôćĺ  return { conversation, warnings, detectedPlatform: platform };
119Ôćĺ}
