121Ôćĺ// ---------------------------------------------------------------------------
122Ôćĺ// DOM message extraction
123Ôćĺ// ---------------------------------------------------------------------------
124Ôćĺ
125Ôćĺfunction extractMessagesFromDom(
126Ôćĺ  document: Document,
127Ôćĺ  domKit: { elementToBlocks: (el: Element) => Array<Record<string, unknown>> },
128Ôćĺ  platform: SourcePlatform,
129Ôćĺ  warnings: string[],
130Ôćĺ): Array<{
131Ôćĺ  id: string;
132Ôćĺ  role: string;
133Ôćĺ  blocks: Array<Record<string, unknown>>;
134Ôćĺ}> {
135Ôćĺ  // Try platform-specific extraction
136Ôćĺ  const platformMessages = extractPlatformSpecific(
137Ôćĺ    document,
138Ôćĺ    domKit,
139Ôćĺ    platform,
140Ôćĺ    warnings,
141Ôćĺ  );
142Ôćĺ  if (platformMessages.length > 0) return platformMessages;
143Ôćĺ
144Ôćĺ  if (platform !== "unknown") {
145Ôćĺ    warnings.push(
146Ôćĺ      `Detected ${platform} but could not extract messages, falling back to generic extraction`,
147Ôćĺ    );
148Ôćĺ  }
149Ôćĺ
150Ôćĺ  // Generic: treat the entire body as a single assistant message
151Ôćĺ  return extractGeneric(document, domKit);
152Ôćĺ}
153Ôćĺ
154Ôćĺfunction extractPlatformSpecific(
155Ôćĺ  document: Document,
156Ôćĺ  domKit: { elementToBlocks: (el: Element) => Array<Record<string, unknown>> },
157Ôćĺ  platform: SourcePlatform,
158Ôćĺ  _warnings: string[],
159Ôćĺ): Array<{
160Ôćĺ  id: string;
161Ôćĺ  role: string;
162Ôćĺ  blocks: Array<Record<string, unknown>>;
163Ôćĺ}> {
164Ôćĺ  const messages: Array<{
165Ôćĺ    id: string;
166Ôćĺ    role: string;
167Ôćĺ    blocks: Array<Record<string, unknown>>;
168Ôćĺ  }> = [];
169Ôćĺ
170Ôćĺ  if (platform === "chatgpt") {
171Ôćĺ    // ChatGPT uses data-message-author-role attribute
172Ôćĺ    const turns = document.querySelectorAll("[data-message-author-role]");
173Ôćĺ    for (const turn of turns) {
174Ôćĺ      const role =
175Ôćĺ        turn.getAttribute("data-message-author-role") === "user"
176Ôćĺ          ? "user"
177Ôćĺ          : "assistant";
178Ôćĺ      const blocks = domKit.elementToBlocks(turn as Element);
179Ôćĺ      if (blocks.length > 0) {
180Ôćĺ        messages.push({ id: crypto.randomUUID(), role, blocks });
181Ôćĺ      }
182Ôćĺ    }
183Ôćĺ  }
184Ôćĺ
185Ôćĺ  // Additional platform-specific selectors can be added here
186Ôćĺ
187Ôćĺ  return messages;
188Ôćĺ}
189Ôćĺ
190Ôćĺfunction extractGeneric(
191Ôćĺ  document: Document,
192Ôćĺ  domKit: { elementToBlocks: (el: Element) => Array<Record<string, unknown>> },
193Ôćĺ): Array<{
194Ôćĺ  id: string;
195Ôćĺ  role: string;
196Ôćĺ  blocks: Array<Record<string, unknown>>;
197Ôćĺ}> {
198Ôćĺ  const body = document.body;
199Ôćĺ  if (!body) return [];
200Ôćĺ
201Ôćĺ  const blocks = domKit.elementToBlocks(body);
202Ôćĺ  if (blocks.length === 0) return [];
203Ôćĺ
204Ôćĺ  return [
205Ôćĺ    {
206Ôćĺ      id: crypto.randomUUID(),
207Ôćĺ      role: "unknown",
208Ôćĺ      blocks,
209Ôćĺ    },
210Ôćĺ  ];
211Ôćĺ}
212Ôćĺ
213Ôćĺfunction extractTitleFromDom(
214Ôćĺ  document: Document,
215Ôćĺ  _platform: SourcePlatform,
216Ôćĺ): string | null {
217Ôćĺ  // Try <title> first
218Ôćĺ  const title = document.querySelector("title")?.textContent?.trim();
219Ôćĺ  if (title) return title;
220Ôćĺ
221Ôćĺ  // Try first <h1>
222Ôćĺ  const h1 = document.querySelector("h1")?.textContent?.trim();
223Ôćĺ  if (h1) return h1;
224Ôćĺ
225Ôćĺ  return null;
226Ôćĺ}
