228Ôćĺ// ---------------------------------------------------------------------------
229Ôćĺ// Plain-text path
230Ôćĺ// ---------------------------------------------------------------------------
231Ôćĺ
232Ôćĺconst ROLE_HEADERS: Record<string, "user" | "assistant"> = {
233Ôćĺ  you: "user",
234Ôćĺ  user: "user",
235Ôćĺ  human: "user",
236Ôćĺ  claude: "assistant",
237Ôćĺ  chatgpt: "assistant",
238Ôćĺ  assistant: "assistant",
239Ôćĺ  grok: "assistant",
240Ôćĺ  gemini: "assistant",
241Ôćĺ  deepseek: "assistant",
242Ôćĺ  perplexity: "assistant",
243Ôćĺ};
244Ôćĺ
245Ôćĺconst PLATFORM_FROM_HEADER: Record<string, SourcePlatform> = {
246Ôćĺ  claude: "claude",
247Ôćĺ  chatgpt: "chatgpt",
248Ôćĺ  grok: "grok",
249Ôćĺ  gemini: "gemini",
250Ôćĺ  deepseek: "deepseek",
251Ôćĺ  perplexity: "perplexity",
252Ôćĺ};
253Ôćĺ
254Ôćĺfunction importFromClipboardText(
255Ôćĺ  text: string,
256Ôćĺ  warnings: string[],
257Ôćĺ): ClipboardImportResult {
258Ôćĺ  const lines = text.split("\n");
259Ôćĺ  const messages: Array<{
260Ôćĺ    id: string;
261Ôćĺ    role: string;
262Ôćĺ    blocks: Array<{ type: string; text: string }>;
263Ôćĺ  }> = [];
264Ôćĺ  let currentRole: "user" | "assistant" | null = null;
265Ôćĺ  let currentContent: string[] = [];
266Ôćĺ  let detectedPlatform: SourcePlatform = "unknown";
267Ôćĺ
268Ôćĺ  for (const line of lines) {
269Ôćĺ    const trimmed = line.trim();
270Ôćĺ    const normalizedHeader = trimmed.toLowerCase().replace(/:$/, "");
271Ôćĺ    const headerRole = ROLE_HEADERS[normalizedHeader];
272Ôćĺ
273Ôćĺ    if (headerRole) {
274Ôćĺ      // Flush previous message
275Ôćĺ      if (currentRole && currentContent.length > 0) {
276Ôćĺ        const content = currentContent.join("\n").trim();
277Ôćĺ        if (content) {
278Ôćĺ          messages.push({
279Ôćĺ            id: crypto.randomUUID(),
280Ôćĺ            role: currentRole,
281Ôćĺ            blocks: [{ type: "paragraph", text: content }],
282Ôćĺ          });
283Ôćĺ        }
284Ôćĺ      }
285Ôćĺ      currentRole = headerRole;
286Ôćĺ      currentContent = [];
287Ôćĺ
288Ôćĺ      // Detect platform from header
289Ôćĺ      if (
290Ôćĺ        detectedPlatform === "unknown" &&
291Ôćĺ        PLATFORM_FROM_HEADER[normalizedHeader]
292Ôćĺ      ) {
293Ôćĺ        detectedPlatform = PLATFORM_FROM_HEADER[normalizedHeader];
294Ôćĺ      }
295Ôćĺ    } else {
296Ôćĺ      currentContent.push(line);
297Ôćĺ    }
298Ôćĺ  }
299Ôćĺ
300Ôćĺ  // Flush last message
301Ôćĺ  if (currentRole && currentContent.length > 0) {
302Ôćĺ    const content = currentContent.join("\n").trim();
303Ôćĺ    if (content) {
304Ôćĺ      messages.push({
305Ôćĺ        id: crypto.randomUUID(),
306Ôćĺ        role: currentRole,
307Ôćĺ        blocks: [{ type: "paragraph", text: content }],
308Ôćĺ      });
309Ôćĺ    }
310Ôćĺ  }
311Ôćĺ
312Ôćĺ  if (messages.length === 0) {
313Ôćĺ    warnings.push(
314Ôćĺ      "No role headers found in plain text. Creating single message.",
315Ôćĺ    );
316Ôćĺ    messages.push({
317Ôćĺ      id: crypto.randomUUID(),
318Ôćĺ      role: "unknown",
319Ôćĺ      blocks: [{ type: "paragraph", text: text.trim() }],
320Ôćĺ    });
321Ôćĺ  }
322Ôćĺ
323Ôćĺ  warnings.push("Imported from plain text ÔÇö formatting may be lost.");
324Ôćĺ
325Ôćĺ  const conversation = conversationSchema.parse({
326Ôćĺ    id: crypto.randomUUID(),
327Ôćĺ    title: "Pasted Chat",
328Ôćĺ    source: { url: "clipboard://paste", platform: detectedPlatform },
329Ôćĺ    messages,
330Ôćĺ  });
331Ôćĺ
332Ôćĺ  return {
333Ôćĺ    conversation,
334Ôćĺ    warnings,
335Ôćĺ    detectedPlatform,
336Ôćĺ  };
337Ôćĺ}
