339Ôćĺ// ---------------------------------------------------------------------------
340Ôćĺ// Helpers
341Ôćĺ// ---------------------------------------------------------------------------
342Ôćĺ
343Ôćĺfunction createSingleMessageResult(
344Ôćĺ  text: string,
345Ôćĺ  platform: SourcePlatform,
346Ôćĺ  warnings: string[],
347Ôćĺ): ClipboardImportResult {
348Ôćĺ  const conversation = conversationSchema.parse({
349Ôćĺ    id: crypto.randomUUID(),
350Ôćĺ    title: "Pasted Chat",
351Ôćĺ    source: { url: "clipboard://paste", platform },
352Ôćĺ    messages: [
353Ôćĺ      {
354Ôćĺ        id: crypto.randomUUID(),
355Ôćĺ        role: "unknown",
356Ôćĺ        blocks: text ? [{ type: "paragraph", text }] : [],
357Ôćĺ      },
358Ôćĺ    ],
359Ôćĺ  });
360Ôćĺ
361Ôćĺ  return { conversation, warnings, detectedPlatform: platform };
362Ôćĺ}
