 60Ôćĺfunction getBodyInputRecord(body: Record<string, unknown>, index: number) {
 61Ôćĺ  const { input } = body;
 62Ôćĺ
 63Ôćĺ  if (!Array.isArray(input)) {
 64Ôćĺ    return null;
 65Ôćĺ  }
 66Ôćĺ
 67Ôćĺ  const entry = input[index];
 68Ôćĺ
 69Ôćĺ  if (!entry || typeof entry !== "object" || Array.isArray(entry)) {
 70Ôćĺ    return null;
 71Ôćĺ  }
 72Ôćĺ
 73Ôćĺ  return entry as Record<string, unknown>;
 74Ôćĺ}
 75Ôćĺ
 76Ôćĺfunction getBodyInputText(body: Record<string, unknown>, index: number) {
 77Ôćĺ  const entry = getBodyInputRecord(body, index);
 78Ôćĺ  const content = entry?.content;
 79Ôćĺ
 80Ôćĺ  if (!Array.isArray(content)) {
 81Ôćĺ    return "";
 82Ôćĺ  }
 83Ôćĺ
 84Ôćĺ  const firstContentPart = content[0];
 85Ôćĺ
 86Ôćĺ  if (
 87Ôćĺ    !firstContentPart ||
 88Ôćĺ    typeof firstContentPart !== "object" ||
 89Ôćĺ    Array.isArray(firstContentPart)
 90Ôćĺ  ) {
 91Ôćĺ    return "";
 92Ôćĺ  }
 93Ôćĺ
 94Ôćĺ  return typeof firstContentPart.text === "string" ? firstContentPart.text : "";
 95Ôćĺ}
