441Ôćĺasync function startMockOpenAiServer(): Promise<ManagedMockServer> {
442Ôćĺ  const server = http.createServer(async (request, response) => {
443Ôćĺ    if (request.method !== "POST" || request.url !== "/v1/responses") {
