445Ôćĺ      return;
446Ôćĺ    }
447Ôćĺ
448Ôćĺ    const rawBody = await readRequestBody(request);
449Ôćĺ    const body = JSON.parse(rawBody) as Record<string, unknown>;
450Ôćĺ    const isPreviewCompilation = Boolean(
451Ôćĺ      (body.text as Record<string, unknown> | undefined)?.format,
452Ôćĺ    );
