454Ôćĺ    const payload = isPreviewCompilation
455Ôćĺ      ? {
456Ôćĺ          output_text: JSON.stringify(buildMockPreviewResponse(body)),
457Ôćĺ        }
458Ôćĺ      : isFollowUp
459Ôćĺ        ? buildMockFollowUpResponse(body)
460Ôćĺ        : buildMockChatResponse(body);
461Ôćĺ
462Ôćĺ    response.writeHead(200, {
463Ôćĺ      "Content-Type": "application/json",
464Ôćĺ    });
465Ôćĺ    response.end(JSON.stringify(payload));
466Ôćĺ  });
467Ôćĺ
468Ôćĺ  await new Promise<void>((resolve, reject) => {
