470Ôćĺ    server.once("error", reject);
471Ôćĺ  });
472Ôćĺ
473Ôćĺ  return {
474Ôćĺ    close: async () => {
475Ôćĺ      await new Promise<void>((resolve, reject) => {
476Ôćĺ        server.close((error) => {
477Ôćĺ          if (error) {
478Ôćĺ            reject(error);
479Ôćĺ            return;
480Ôćĺ          }
481Ôćĺ
482Ôćĺ          resolve();
