490Ôćĺasync function waitForPort(port: number, label: string) {
491Ôćĺ  const startedAt = Date.now();
492Ôćĺ
493Ôćĺ  while (Date.now() - startedAt < 45_000) {
494Ôćĺ    try {
495Ôćĺ      await new Promise<void>((resolve, reject) => {
496Ôćĺ        const socket = net.createConnection(
497Ôćĺ          {
498Ôćĺ            host: "127.0.0.1",
499Ôćĺ            port,
500Ôćĺ          },
501Ôćĺ          () => {
502Ôćĺ            socket.end();
503Ôćĺ            resolve();
504Ôćĺ          },
505Ôćĺ        );
506Ôćĺ
507Ôćĺ        socket.setTimeout(1_000);
508Ôćĺ        socket.once("timeout", () => {
509Ôćĺ          socket.destroy();
510Ôćĺ          reject(new Error("timeout"));
511Ôćĺ        });
512Ôćĺ        socket.once("error", reject);
513Ôćĺ      });
514Ôćĺ      return;
515Ôćĺ    } catch {
516Ôćĺ      // Retry until timeout.
517Ôćĺ    }
518Ôćĺ
519Ôćĺ    await delay(500);
520Ôćĺ  }
521Ôćĺ
522Ôćĺ  throw new Error(`Timed out while waiting for ${label} on port ${port}.`);
523Ôćĺ}
