 40Ôćĺ    case "heading":
 41Ôćĺ      return {
 42Ôćĺ        id: original.id,
 43Ôćĺ        type: "heading",
 44Ôćĺ        level: original.level,
 45Ôćĺ        text: element.textContent ?? "",
 46Ôćĺ      };
 47Ôćĺ
 48Ôćĺ    case "quote":
 49Ôćĺ      return {
 50Ôćĺ        id: original.id,
 51Ôćĺ        type: "quote",
 52Ôćĺ        text: element.textContent ?? "",
