 54Ôćĺ
 55Ôćĺ    case "code": {
 56Ôćĺ      const codeEl = element.querySelector("pre code");
 57Ôćĺ      return {
 58Ôćĺ        id: original.id,
 59Ôćĺ        type: "code",
 60Ôćĺ        language: original.language,
 61Ôćĺ        text: codeEl ? (codeEl.textContent ?? "") : (element.textContent ?? ""),
 62Ôćĺ      };
 63Ôćĺ    }
 64Ôćĺ
 65Ôćĺ    case "list": {
 66Ôćĺ      const listItems = element.querySelectorAll("li");
 67Ôćĺ      const items = Array.from(listItems).map((li) => li.textContent ?? "");
 68Ôćĺ      return {
