 78Ôćĺ      const headers = Array.from(thElements).map((th) => th.textContent ?? "");
 79Ôćĺ
 80Ôćĺ      const bodyRows = element.querySelectorAll("tbody tr");
 81Ôćĺ      const rows = Array.from(bodyRows).map((tr) => {
 82Ôćĺ        const cells = tr.querySelectorAll("td");
 83Ôćĺ        return Array.from(cells).map((td) => td.textContent ?? "");
