445Ôćĺexport function ReaderView({
446Ôćĺ  activeRules,
447Ôćĺ  adjustModeEnabled,
448Ôćĺ  conversation,
449Ôćĺ  deletedMessageIds,
450Ôćĺ  editMode,
451Ôćĺ  effectsMap,
452Ôćĺ  highlightedRuleId,
453Ôćĺ  onBlocksChange,
454Ôćĺ  onCopyMessage,
455Ôćĺ  onDeleteMessage,
456Ôćĺ  onDeleteRound,
457Ôćĺ  onRestoreMessage,
458Ôćĺ  onSelectBlock,
459Ôćĺ  selectedBlock,
460Ôćĺ  showDeleted,
461Ôćĺ}: ReaderViewProps) {
462Ôćĺ  const visibleMessages = useMemo(() => {
463Ôćĺ    if (!conversation?.messages) return [];
464Ôćĺ    if (!deletedMessageIds?.size) return conversation.messages;
465Ôćĺ    if (showDeleted) return conversation.messages;
466Ôćĺ    return conversation.messages.filter((m) => !deletedMessageIds.has(m.id));
467Ôćĺ  }, [conversation?.messages, deletedMessageIds, showDeleted]);
468Ôćĺ
469Ôćĺ  // Tracks the latest in-progress blocks per message so that consecutive edits
470Ôćĺ  // within the same debounce window build on top of each other rather than on
471Ôćĺ  // stale props (which would cause earlier edits to be overwritten).
472Ôćĺ  const pendingBlocksRef = useRef<Map<string, Block[]>>(new Map());
473Ôćĺ
474Ôćĺ  // When the conversation prop updates (i.e. the parent has persisted the edit
475Ôćĺ  // and passed the new data back down), clear any pending entries whose blocks
476Ôćĺ  // now match the incoming props ÔÇö they are no longer "in-flight".
477Ôćĺ  useEffect(() => {
478Ôćĺ    if (!conversation) return;
479Ôćĺ    const pending = pendingBlocksRef.current;
480Ôćĺ    for (const [messageId] of pending) {
481Ôćĺ      const message = conversation.messages.find((m) => m.id === messageId);
482Ôćĺ      if (!message) {
483Ôćĺ        pending.delete(messageId);
484Ôćĺ        continue;
485Ôćĺ      }
486Ôćĺ      // If the prop blocks now reflect our last pending write, the save has
487Ôćĺ      // been acknowledged ÔÇö remove the entry so the next edit starts fresh.
488Ôćĺ      const pendingBlocks = pending.get(messageId);
489Ôćĺ      if (
490Ôćĺ        pendingBlocks &&
491Ôćĺ        pendingBlocks.length === message.blocks.length &&
492Ôćĺ        pendingBlocks.every((b, i) => b === message.blocks[i])
493Ôćĺ      ) {
494Ôćĺ        pending.delete(messageId);
495Ôćĺ      }
496Ôćĺ    }
497Ôćĺ  }, [conversation]);
498Ôćĺ
499Ôćĺ  const highlightedBlocks = useMemo(() => {
500Ôćĺ    if (!highlightedRuleId || !conversation) {
501Ôćĺ      return new Set<string>();
502Ôćĺ    }
503Ôćĺ
504Ôćĺ    const rule = activeRules.find(
505Ôćĺ      (r) => r.id === highlightedRuleId && r.status === "active",
506Ôćĺ    );
507Ôćĺ
508Ôćĺ    if (!rule) {
509Ôćĺ      return new Set<string>();
510Ôćĺ    }
511Ôćĺ
512Ôćĺ    const matches = getBlocksMatchingRule(rule, conversation);
513Ôćĺ    return new Set(matches.map((m) => `${m.messageId}:${m.blockId}`));
514Ôćĺ  }, [highlightedRuleId, activeRules, conversation]);
515Ôćĺ
516Ôćĺ  const handleBlockChange = useCallback(
517Ôćĺ    (messageId: string, blockIndex: number, newBlock: Block) => {
518Ôćĺ      if (!onBlocksChange || !conversation) return;
519Ôćĺ      const message = conversation.messages.find((m) => m.id === messageId);
520Ôćĺ      if (!message) return;
521Ôćĺ
522Ôćĺ      // Use pending blocks as the base if present (prevents stale-closure
523Ôćĺ      // overwrites when the user edits multiple blocks before the debounced
524Ôćĺ      // save propagates updated props back down).
525Ôćĺ      const baseBlocks =
526Ôćĺ        pendingBlocksRef.current.get(messageId) ?? message.blocks;
527Ôćĺ
528Ôćĺ      const updatedBlocks = baseBlocks.map((b, i) =>
529Ôćĺ        i === blockIndex ? newBlock : b,
530Ôćĺ      );
531Ôćĺ
532Ôćĺ      pendingBlocksRef.current.set(messageId, updatedBlocks);
533Ôćĺ      onBlocksChange(messageId, updatedBlocks);
534Ôćĺ    },
535Ôćĺ    [onBlocksChange, conversation],
536Ôćĺ  );
537Ôćĺ
538Ôćĺ  if (!conversation?.messages.length) {
539Ôćĺ    return (
540Ôćĺ      <div className="rounded-2xl border border-border/80 bg-card/75 px-4 py-5 text-sm text-muted-foreground">
541Ôćĺ        F├╝r diesen Import ist noch kein Transkriptinhalt verf├╝gbar.
542Ôćĺ      </div>
543Ôćĺ    );
544Ôćĺ  }
545Ôćĺ
546Ôćĺ  return (
547Ôćĺ    <div className="space-y-3">
548Ôćĺ      {visibleMessages.map((message, index) => (
549Ôćĺ        <ReaderMessage
550Ôćĺ          key={message.id}
551Ôćĺ          adjustModeEnabled={adjustModeEnabled}
552Ôćĺ          editMode={editMode}
553Ôćĺ          effectsMap={effectsMap}
554Ôćĺ          highlightedBlocks={highlightedBlocks}
555Ôćĺ          message={message}
556Ôćĺ          messageIndex={index}
557Ôćĺ          onBlockChange={editMode ? handleBlockChange : undefined}
558Ôćĺ          onBlocksChange={editMode ? onBlocksChange : undefined}
559Ôćĺ          onCopyMessage={
560Ôćĺ            onCopyMessage ? () => onCopyMessage(message.id) : undefined
561Ôćĺ          }
562Ôćĺ          onSelectBlock={onSelectBlock}
563Ôćĺ          selectedBlock={selectedBlock}
564Ôćĺ          isDeleted={deletedMessageIds?.has(message.id)}
565Ôćĺ          onDeleteMessage={
566Ôćĺ            onDeleteMessage ? () => onDeleteMessage(message.id) : undefined
567Ôćĺ          }
568Ôćĺ          onDeleteRound={
569Ôćĺ            onDeleteRound ? () => onDeleteRound(message.id) : undefined
570Ôćĺ          }
571Ôćĺ          onRestore={
572Ôćĺ            onRestoreMessage
573Ôćĺ              ? () => {
574Ôćĺ                  void onRestoreMessage(message.id);
575Ôćĺ                }
576Ôćĺ              : undefined
577Ôćĺ          }
578Ôćĺ        />
579Ôćĺ      ))}
580Ôćĺ    </div>
581Ôćĺ  );
582Ôćĺ}
