 252Ôćĺfunction collectParagraphRepairSignals(message: StructuredSnapshotMessage) {
 253Ôćĺ  const signals: Array<{
 254Ôćĺ    blockIndex: number;
 255Ôćĺ    reasons: string[];
 256Ôćĺ    score: number;
 257Ôćĺ  }> = [];
 258Ôćĺ
 259Ôćĺ  for (const [blockIndex, block] of message.blocks.entries()) {
 260Ôćĺ    if (block.type !== "paragraph" && block.type !== "quote") {
 261Ôćĺ      continue;
 262Ôćĺ    }
 263Ôćĺ
 264Ôćĺ    const reasons = new Set<string>();
 265Ôćĺ    let score = 0;
 266Ôćĺ
 267Ôćĺ    if (countMatches(block.text, EMPHASIZED_STEP_PATTERN) >= 2) {
 268Ôćĺ      reasons.add("markdown-step-paragraph");
 269Ôćĺ      score += 4;
 270Ôćĺ    }
 271Ôćĺ
 272Ôćĺ    const syntaxMatches = countMatches(
 273Ôćĺ      block.text,
 274Ôćĺ      PARAGRAPH_BLOCK_SYNTAX_PATTERN,
 275Ôćĺ    );
 276Ôćĺ
 277Ôćĺ    if (syntaxMatches >= 2 && block.text.includes("\n")) {
 278Ôćĺ      reasons.add("block-markdown-leaked-into-paragraph");
 279Ôćĺ      score += 4;
 280Ôćĺ    }
 281Ôćĺ
 282Ôćĺ    if (block.text.includes("```")) {
 283Ôćĺ      reasons.add("code-fence-leaked-into-paragraph");
 284Ôćĺ      score += 5;
 285Ôćĺ    }
 286Ôćĺ
