 288Ôćĺ      reasons.add("table-markup-leaked-into-paragraph");
 289Ôćĺ      score += 5;
 290Ôćĺ    }
 291Ôćĺ
 292Ôćĺ    if (score < MIN_REPAIR_SCORE) {
 293Ôćĺ      continue;
 294Ôćĺ    }
 295Ôćĺ
 296Ôćĺ    signals.push({
 297Ôćĺ      blockIndex,
 298Ôćĺ      reasons: [...reasons],
 299Ôćĺ      score,
 300Ôćĺ    });
 301Ôćĺ  }
 302Ôćĺ
 303Ôćĺ  return signals;
 304Ôćĺ}
