 344Ôćĺfunction detectMessageRepairCandidate(message: StructuredSnapshotMessage) {
 345Ôćĺ  if (message.role !== "assistant" || !message.rawText?.trim()) {
 346Ôćĺ    return null;
 347Ôćĺ  }
 348Ôćĺ
 349Ôćĺ  const reasons = new Set<string>();
 350Ôćĺ  let score = 0;
 351Ôćĺ
 352Ôćĺ  if (message.parser.usedFallback) {
 353Ôćĺ    reasons.add("fallback");
 354Ôćĺ    score += 8;
 355Ôćĺ  }
 356Ôćĺ
 357Ôćĺ  if (
 358Ôćĺ    message.blocks.length === 1 &&
 359Ôćĺ    message.blocks[0]?.type === "paragraph" &&
 360Ôćĺ    (STRUCTURE_HINT_PATTERN.test(message.rawText) ||
 361Ôćĺ      message.rawHtml?.includes("<pre") ||
 362Ôćĺ      message.rawHtml?.includes("<table") ||
 363Ôćĺ      message.rawHtml?.includes("<ul") ||
 364Ôćĺ      message.rawHtml?.includes("<ol") ||
 365Ôćĺ      message.rawHtml?.includes("<blockquote"))
 366Ôćĺ  ) {
