 368Ôćĺ    score += 6;
 369Ôćĺ  }
 370Ôćĺ
 371Ôćĺ  const rawHtmlSignals = collectRawHtmlRepairSignals(message);
 372Ôćĺ
 373Ôćĺ  for (const reason of rawHtmlSignals.reasons) {
 374Ôćĺ    reasons.add(reason);
 375Ôćĺ  }
 376Ôćĺ
 377Ôćĺ  score += rawHtmlSignals.score;
 378Ôćĺ
 379Ôćĺ  if (score < MIN_REPAIR_SCORE) {
 380Ôćĺ    return null;
 381Ôćĺ  }
 382Ôćĺ
 383Ôćĺ  return {
 384Ôćĺ    reasons: [...reasons],
 385Ôćĺ    score,
 386Ôćĺ  };
 387Ôćĺ}
