 419Ôćĺ    blocks.map(blockToPlainText).join("\n"),
 420Ôćĺ  );
 421Ôćĺ
 422Ôćĺ  if (!original) {
 423Ôćĺ    return candidate.length === 0;
 424Ôćĺ  }
 425Ôćĺ
 426Ôćĺ  if (!candidate) {
 427Ôćĺ    return false;
 428Ôćĺ  }
 429Ôćĺ
