 460Ôćĺfunction getOutputText(payload: unknown) {
 461Ôćĺ  if (payload && typeof payload === "object" && "output_text" in payload) {
 462Ôćĺ    const outputText = (payload as { output_text?: unknown }).output_text;
 463Ôćĺ    if (typeof outputText === "string" && outputText.trim()) {
 464Ôćĺ      return outputText;
 465Ôćĺ    }
 466Ôćĺ  }
 467Ôćĺ
 468Ôćĺ  if (!payload || typeof payload !== "object" || !("output" in payload)) {
 469Ôćĺ    throw new Error("Responses API payload did not include output text.");
 470Ôćĺ  }
 471Ôćĺ
 472Ôćĺ  const output = (payload as { output?: unknown }).output;
 473Ôćĺ
 474Ôćĺ  if (!Array.isArray(output)) {
 475Ôćĺ    throw new Error("Responses API payload did not include output items.");
 476Ôćĺ  }
 477Ôćĺ
 478Ôćĺ  const text = output
 479Ôćĺ    .flatMap((item) => {
 480Ôćĺ      if (!item || typeof item !== "object" || !("content" in item)) {
 481Ôćĺ        return [];
 482Ôćĺ      }
 483Ôćĺ
 484Ôćĺ      const content = (item as { content?: unknown }).content;
 485Ôćĺ      if (!Array.isArray(content)) {
 486Ôćĺ        return [];
 487Ôćĺ      }
 488Ôćĺ
 489Ôćĺ      return content.flatMap((entry) => {
 490Ôćĺ        if (!entry || typeof entry !== "object") {
 491Ôćĺ          return [];
 492Ôćĺ        }
 493Ôćĺ
 494Ôćĺ        const maybeText = (entry as { text?: unknown }).text;
 495Ôćĺ        return typeof maybeText === "string" && maybeText.trim()
 496Ôćĺ          ? [maybeText]
 497Ôćĺ          : [];
 498Ôćĺ      });
 499Ôćĺ    })
 500Ôćĺ    .join("\n")
 501Ôćĺ    .trim();
 502Ôćĺ
 503Ôćĺ  if (!text) {
 504Ôćĺ    throw new Error(
 505Ôćĺ      "Responses API payload did not contain structured JSON text.",
 506Ôćĺ    );
 507Ôćĺ  }
 508Ôćĺ
 509Ôćĺ  return text;
 510Ôćĺ}
