 604Ôćĺ  if (!value?.trim()) {
 605Ôćĺ    return undefined;
 606Ôćĺ  }
 607Ôćĺ
 608Ôćĺ  const normalizedNeedle = needle.trim();
 609Ôćĺ  if (!normalizedNeedle) {
 610Ôćĺ    return value.slice(0, radius * 2);
 611Ôćĺ  }
 612Ôćĺ
 613Ôćĺ  const searchNeedle = normalizedNeedle.slice(0, 96);
 614Ôćĺ  const matchIndex = value.indexOf(searchNeedle);
 615Ôćĺ
 616Ôćĺ  if (matchIndex < 0) {
 617Ôćĺ    return value.slice(0, radius * 2);
 618Ôćĺ  }
 619Ôćĺ
 620Ôćĺ  const start = Math.max(0, matchIndex - radius);
 621Ôćĺ  const end = Math.min(value.length, matchIndex + searchNeedle.length + radius);
 622Ôćĺ  return value.slice(start, end);
