 884Ôćĺasync function mapWithConcurrency<T, TResult>(
 885Ôćĺ  items: T[],
 886Ôćĺ  concurrency: number,
 887Ôćĺ  mapper: (item: T) => Promise<TResult>,
 888Ôćĺ) {
 889Ôćĺ  const results: TResult[] = new Array(items.length);
 890Ôćĺ  let nextIndex = 0;
 891Ôćĺ
 892Ôćĺ  async function worker() {
 893Ôćĺ    while (nextIndex < items.length) {
 894Ôćĺ      const currentIndex = nextIndex;
 895Ôćĺ      nextIndex += 1;
 896Ôćĺ      results[currentIndex] = await mapper(items[currentIndex]!);
 897Ôćĺ    }
 898Ôćĺ  }
 899Ôćĺ
 900Ôćĺ  await Promise.all(
 901Ôćĺ    Array.from({ length: Math.min(concurrency, items.length) }, () => worker()),
 902Ôćĺ  );
 903Ôćĺ
 904Ôćĺ  return results;
 905Ôćĺ}
