 34Ôćĺexport function resolveReaderBlockEffects(
 35Ôćĺ  rules: FormatRule[],
 36Ôćĺ  messageId: string,
 37Ôćĺ  blockIndex: number,
 38Ôćĺ  blockType: Block["type"],
 39Ôćĺ  blockText: string,
 40Ôćĺ  context?: ReaderMatchContext,
