 44Ôćĺ    .filter(
 45Ôćĺ      (rule) =>
 46Ôćĺ        rule.status === "active" &&
 47Ôćĺ        matchesReaderRule(
 48Ôćĺ          rule,
 49Ôćĺ          messageId,
 50Ôćĺ          blockIndex,
 51Ôćĺ          blockType,
 52Ôćĺ          blockText,
 53Ôćĺ          context,
 54Ôćĺ          blockId,
 55Ôćĺ        ),
 56Ôćĺ    )
 57Ôćĺ    .map((rule) => rule.compiledRule)
