 62Ôćĺexport function buildReaderEffectsMap(
 63Ôćĺ  rules: FormatRule[],
 64Ôćĺ  conversation: Conversation,
 65Ôćĺ): Map<string, RuleEffect[]> {
 66Ôćĺ  const activeRules = rules.filter((r) => r.status === "active");
 67Ôćĺ  const effectsMap = new Map<string, RuleEffect[]>();
 68Ôćĺ
 69Ôćĺ  for (const message of conversation.messages) {
 70Ôćĺ    const context: ReaderMatchContext = {
 71Ôćĺ      messageRole: message.role,
 72Ôćĺ      blocks: message.blocks,
 73Ôćĺ    };
 74Ôćĺ
 75Ôćĺ    for (
 76Ôćĺ      let blockIndex = 0;
 77Ôćĺ      blockIndex < message.blocks.length;
 78Ôćĺ      blockIndex += 1
 79Ôćĺ    ) {
 80Ôćĺ      const block = message.blocks[blockIndex];
 81Ôćĺ
 82Ôćĺ      if (!block) {
 83Ôćĺ        continue;
 84Ôćĺ      }
 85Ôćĺ
 86Ôćĺ      const effects = activeRules
 87Ôćĺ        .filter((rule) =>
 88Ôćĺ          matchesReaderRule(
 89Ôćĺ            rule,
 90Ôćĺ            message.id,
 91Ôćĺ            blockIndex,
 92Ôćĺ            block.type,
 93Ôćĺ            blockToPlainText(block),
 94Ôćĺ            context,
 95Ôćĺ            block.id,
 96Ôćĺ          ),
 97Ôćĺ        )
 98Ôćĺ        .map((rule) => rule.compiledRule)
 99Ôćĺ        .filter((effect): effect is RuleEffect => effect !== undefined)
100Ôćĺ        .map(normalizeLegacyEffect);
101Ôćĺ
102Ôćĺ      if (effects.length > 0) {
103Ôćĺ        effectsMap.set(`${message.id}:${block.id}`, effects);
104Ôćĺ      }
105Ôćĺ    }
106Ôćĺ  }
107Ôćĺ
108Ôćĺ  return effectsMap;
109Ôćĺ}
