111Ôćĺexport function applyMarkdownRules(content: string, rules: FormatRule[]) {
112Ôćĺ  const lines = content.split("\n");
113Ôćĺ  const nextLines = [...lines];
114Ôćĺ
115Ôćĺ  for (const rule of rules) {
116Ôćĺ    if (rule.status !== "active") {
117Ôćĺ      continue;
118Ôćĺ    }
119Ôćĺ
120Ôćĺ    const parsedSelector = ruleSelectorSchema.safeParse(rule.selector);
121Ôćĺ    const parsedEffect = ruleEffectSchema.safeParse(rule.compiledRule);
122Ôćĺ
123Ôćĺ    if (!parsedSelector.success || !parsedEffect.success) {
124Ôćĺ      continue;
125Ôćĺ    }
126Ôćĺ
127Ôćĺ    const selector = parsedSelector.data;
128Ôćĺ    const effect = normalizeLegacyEffect(parsedEffect.data);
129Ôćĺ
130Ôćĺ    const strategy = "strategy" in selector ? selector.strategy : undefined;
131Ôćĺ
132Ôćĺ    if (strategy === "compound") {
133Ôćĺ      const transform = effect.markdownTransform;
134Ôćĺ      if (!transform) continue;
135Ôćĺ
136Ôćĺ      // Compound in Markdown: textPattern match on each line
137Ôćĺ      // blockType/messageRole/context not relevant for Markdown (line-based only)
138Ôćĺ      const textPattern =
139Ôćĺ        "textPattern" in selector ? selector.textPattern : null;
140Ôćĺ
141Ôćĺ      for (let index = 0; index < nextLines.length; index += 1) {
142Ôćĺ        const line = nextLines[index] ?? "";
143Ôćĺ
144Ôćĺ        // If textPattern set: only transform matching lines
145Ôćĺ        if (textPattern) {
146Ôćĺ          try {
147Ôćĺ            if (!new RegExp(textPattern).test(line)) continue;
148Ôćĺ          } catch {
149Ôćĺ            continue;
150Ôćĺ          }
151Ôćĺ        }
152Ôćĺ
153Ôćĺ        // Apply transform (same switch logic as for exact)
154Ôćĺ        switch (transform) {
155Ôćĺ          case "promote_to_heading":
156Ôćĺ            nextLines[index] = `## ${line.replace(/^#+\s*/, "")}`.trimEnd();
157Ôćĺ            break;
158Ôćĺ          case "bold_prefix_before_colon":
159Ôćĺ            nextLines[index] = line.replace(
160Ôćĺ              /^([^:\n]{1,120}:)(?!\*)/,
161Ôćĺ              "**$1**",
162Ôćĺ            );
163Ôćĺ            break;
164Ôćĺ          case "normalize_list_structure": {
165Ôćĺ            const trimmedLine = line.trim();
166Ôćĺ            if (!trimmedLine) break;
167Ôćĺ            nextLines[index] = /^[-*]\s/.test(trimmedLine)
168Ôćĺ              ? trimmedLine
169Ôćĺ              : `- ${trimmedLine}`;
170Ôćĺ            break;
171Ôćĺ          }
172Ôćĺ          case "normalize_markdown_table":
173Ôćĺ            if (line.includes("|")) {
174Ôćĺ              nextLines[index] = line
175Ôćĺ                .split("|")
176Ôćĺ                .map((cell) => cell.trim())
177Ôćĺ                .join(" | ")
178Ôćĺ                .trim();
179Ôćĺ            }
180Ôćĺ            break;
181Ôćĺ          case "reshape_markdown_block":
182Ôćĺ            nextLines[index] = line.trimEnd();
183Ôćĺ            break;
184Ôćĺ        }
185Ôćĺ      }
186Ôćĺ      continue;
187Ôćĺ    }
188Ôćĺ
189Ôćĺ    // All effects are now custom_style after normalization
190Ôćĺ    {
191Ôćĺ      const transform = effect.markdownTransform;
192Ôćĺ      if (!transform) continue;
193Ôćĺ
194Ôćĺ      if (
195Ôćĺ        strategy === "prefix_before_colon" &&
196Ôćĺ        transform === "bold_prefix_before_colon"
197Ôćĺ      ) {
198Ôćĺ        for (let index = 0; index < nextLines.length; index += 1) {
199Ôćĺ          const line = nextLines[index] ?? "";
200Ôćĺ          nextLines[index] = line.replace(/^([^:\n]{1,120}:)(?!\*)/, "**$1**");
201Ôćĺ        }
202Ôćĺ        continue;
203Ôćĺ      }
204Ôćĺ
205Ôćĺ      if (
206Ôćĺ        strategy === "markdown_table" &&
207Ôćĺ        transform === "normalize_markdown_table"
208Ôćĺ      ) {
209Ôćĺ        for (let index = 0; index < nextLines.length; index += 1) {
210Ôćĺ          const line = nextLines[index] ?? "";
211Ôćĺ          if (!line.includes("|")) continue;
212Ôćĺ          nextLines[index] = line
213Ôćĺ            .split("|")
214Ôćĺ            .map((cell) => cell.trim())
215Ôćĺ            .join(" | ")
216Ôćĺ            .trim();
217Ôćĺ        }
218Ôćĺ        continue;
219Ôćĺ      }
220Ôćĺ
221Ôćĺ      const lineStart = "lineStart" in selector ? selector.lineStart : null;
222Ôćĺ      const lineEnd = "lineEnd" in selector ? selector.lineEnd : lineStart;
223Ôćĺ      if (!lineStart || !lineEnd) continue;
224Ôćĺ      const startIndex = Math.max(0, lineStart - 1);
225Ôćĺ      const endIndex = Math.min(nextLines.length - 1, lineEnd - 1);
226Ôćĺ
227Ôćĺ      switch (transform) {
228Ôćĺ        case "promote_to_heading":
229Ôćĺ          nextLines[startIndex] =
230Ôćĺ            `## ${nextLines[startIndex]?.replace(/^#+\s*/, "") ?? ""}`.trimEnd();
231Ôćĺ          break;
232Ôćĺ        case "bold_prefix_before_colon":
233Ôćĺ          for (let index = startIndex; index <= endIndex; index += 1) {
234Ôćĺ            const line = nextLines[index] ?? "";
235Ôćĺ            nextLines[index] = line.replace(
236Ôćĺ              /^([^:\n]{1,120}:)(?!\*)/,
237Ôćĺ              "**$1**",
238Ôćĺ            );
239Ôćĺ          }
240Ôćĺ          break;
241Ôćĺ        case "normalize_list_structure":
242Ôćĺ          for (let index = startIndex; index <= endIndex; index += 1) {
243Ôćĺ            const line = nextLines[index] ?? "";
244Ôćĺ            const trimmedLine = line.trim();
245Ôćĺ            if (!trimmedLine) continue;
246Ôćĺ            nextLines[index] = /^[-*]\s/.test(trimmedLine)
247Ôćĺ              ? trimmedLine
248Ôćĺ              : `- ${trimmedLine}`;
249Ôćĺ          }
250Ôćĺ          break;
251Ôćĺ        case "normalize_markdown_table":
252Ôćĺ          for (let index = startIndex; index <= endIndex; index += 1) {
253Ôćĺ            const line = nextLines[index] ?? "";
254Ôćĺ            nextLines[index] = line
255Ôćĺ              .split("|")
256Ôćĺ              .map((cell) => cell.trim())
257Ôćĺ              .join(" | ")
258Ôćĺ              .trim();
259Ôćĺ          }
260Ôćĺ          break;
261Ôćĺ        case "reshape_markdown_block":
262Ôćĺ          for (let index = startIndex; index <= endIndex; index += 1) {
263Ôćĺ            nextLines[index] = (nextLines[index] ?? "").trimEnd();
264Ôćĺ          }
265Ôćĺ          break;
266Ôćĺ      }
267Ôćĺ    }
268Ôćĺ  }
269Ôćĺ
270Ôćĺ  return nextLines.join("\n");
271Ôćĺ}
