 72Ôćĺfunction matchesCompoundSelector(
 73Ôćĺ  selector: CompoundSelector,
 74Ôćĺ  blockType: Block["type"],
 75Ôćĺ  blockText: string,
 76Ôćĺ  blockIndex: number,
 77Ôćĺ  context?: ReaderMatchContext,
 78Ôćĺ): boolean {
 79Ôćĺ  if (selector.blockType !== undefined && selector.blockType !== blockType) {
 80Ôćĺ    return false;
 81Ôćĺ  }
 82Ôćĺ
 83Ôćĺ  if (selector.messageRole !== undefined) {
 84Ôćĺ    if (context === undefined || selector.messageRole !== context.messageRole) {
 85Ôćĺ      return false;
 86Ôćĺ    }
 87Ôćĺ  }
 88Ôćĺ
 89Ôćĺ  if (selector.headingLevel !== undefined) {
 90Ôćĺ    if (blockType !== "heading") {
 91Ôćĺ      return false;
 92Ôćĺ    }
 93Ôćĺ    if (context !== undefined) {
 94Ôćĺ      const block = context.blocks[blockIndex];
 95Ôćĺ      if (
 96Ôćĺ        block === undefined ||
 97Ôćĺ        block.type !== "heading" ||
 98Ôćĺ        block.level !== selector.headingLevel
 99Ôćĺ      ) {
100Ôćĺ        return false;
101Ôćĺ      }
102Ôćĺ    }
103Ôćĺ  }
104Ôćĺ
105Ôćĺ  if (selector.position !== undefined && context !== undefined) {
106Ôćĺ    if (selector.position === "first" && blockIndex !== 0) {
107Ôćĺ      return false;
108Ôćĺ    }
109Ôćĺ    if (
110Ôćĺ      selector.position === "last" &&
111Ôćĺ      blockIndex !== context.blocks.length - 1
112Ôćĺ    ) {
113Ôćĺ      return false;
114Ôćĺ    }
115Ôćĺ  }
116Ôćĺ
117Ôćĺ  if (selector.textPattern !== undefined) {
118Ôćĺ    if (!matchesTextPattern(blockText, selector.textPattern)) {
119Ôćĺ      return false;
120Ôćĺ    }
121Ôćĺ  }
122Ôćĺ
123Ôćĺ  if (selector.context !== undefined && context !== undefined) {
124Ôćĺ    if (selector.context.previousSibling !== undefined) {
125Ôćĺ      const prevBlock = context.blocks[blockIndex - 1];
126Ôćĺ      if (!matchesSiblingFilter(prevBlock, selector.context.previousSibling)) {
127Ôćĺ        return false;
128Ôćĺ      }
129Ôćĺ    }
130Ôćĺ
131Ôćĺ    if (selector.context.nextSibling !== undefined) {
132Ôćĺ      const nextBlock = context.blocks[blockIndex + 1];
133Ôćĺ      if (!matchesSiblingFilter(nextBlock, selector.context.nextSibling)) {
134Ôćĺ        return false;
135Ôćĺ      }
136Ôćĺ    }
137Ôćĺ  }
138Ôćĺ
139Ôćĺ  return true;
140Ôćĺ}
141Ôćĺ
142Ôćĺfunction matchesTextPattern(text: string, pattern: string): boolean {
143Ôćĺ  try {
144Ôćĺ    return new RegExp(pattern).test(text);
145Ôćĺ  } catch {
146Ôćĺ    return false;
147Ôćĺ  }
148Ôćĺ}
149Ôćĺ
150Ôćĺfunction matchesSiblingFilter(
151Ôćĺ  block: Block | undefined,
152Ôćĺ  filter: CompoundContextSibling,
153Ôćĺ): boolean {
154Ôćĺ  if (block === undefined) {
155Ôćĺ    return false;
156Ôćĺ  }
157Ôćĺ
158Ôćĺ  if (filter.blockType !== undefined && block.type !== filter.blockType) {
159Ôćĺ    return false;
160Ôćĺ  }
161Ôćĺ
162Ôćĺ  if (filter.headingLevel !== undefined) {
163Ôćĺ    if (block.type !== "heading" || block.level !== filter.headingLevel) {
164Ôćĺ      return false;
165Ôćĺ    }
166Ôćĺ  }
167Ôćĺ
168Ôćĺ  if (filter.textPattern !== undefined) {
169Ôćĺ    const text =
170Ôćĺ      block.type === "list"
171Ôćĺ        ? block.items.join("\n")
172Ôćĺ        : block.type === "table"
173Ôćĺ          ? [
174Ôćĺ              block.headers.join(" | "),
175Ôćĺ              ...block.rows.map((row) => row.join(" | ")),
176Ôćĺ            ].join("\n")
177Ôćĺ          : block.text;
178Ôćĺ
179Ôćĺ    if (!matchesTextPattern(text, filter.textPattern)) {
180Ôćĺ      return false;
181Ôćĺ    }
182Ôćĺ  }
183Ôćĺ
184Ôćĺ  return true;
185Ôćĺ}
