187Ôćĺexport function getBlocksMatchingRule(
188Ôćĺ  rule: FormatRule,
189Ôćĺ  conversation: Conversation,
190Ôćĺ): Array<{ messageId: string; blockIndex: number; blockId: string }> {
191Ôćĺ  const matches: Array<{
192Ôćĺ    messageId: string;
193Ôćĺ    blockIndex: number;
194Ôćĺ    blockId: string;
