197Ôćĺ  for (const message of conversation.messages) {
198Ôćĺ    const context: ReaderMatchContext = {
199Ôćĺ      messageRole: message.role,
200Ôćĺ      blocks: message.blocks,
201Ôćĺ    };
202Ôćĺ
203Ôćĺ    for (
204Ôćĺ      let blockIndex = 0;
205Ôćĺ      blockIndex < message.blocks.length;
206Ôćĺ      blockIndex += 1
207Ôćĺ    ) {
208Ôćĺ      const block = message.blocks[blockIndex];
209Ôćĺ
210Ôćĺ      if (!block) {
211Ôćĺ        continue;
212Ôćĺ      }
213Ôćĺ
214Ôćĺ      if (
215Ôćĺ        matchesReaderRule(
