 29Ôćĺ    itemStyle: Object.keys(itemStyle).length > 0 ? itemStyle : undefined,
 30Ôćĺ    textStyle: Object.keys(textStyle).length > 0 ? textStyle : undefined,
 31Ôćĺ    textTransform,
