 65Ôćĺfunction downloadBlob(content: string, mimeType: string, filename: string) {
 66Ôćĺ  const blob = new Blob([content], { type: mimeType });
 67Ôćĺ  const url = URL.createObjectURL(blob);
 68Ôćĺ  const a = document.createElement("a");
 69Ôćĺ  a.href = url;
 70Ôćĺ  a.download = filename;
 71Ôćĺ  document.body.appendChild(a);
 72Ôćĺ  a.click();
 73Ôćĺ  document.body.removeChild(a);
 74Ôćĺ  setTimeout(() => URL.revokeObjectURL(url), 100);
 75Ôćĺ}
