 82Ôćĺexport class FormatRegistry {
 83Ôćĺ  private formats = new Map<string, OutputFormatDescriptor>();
 84Ôćĺ
 85Ôćĺ  register(format: OutputFormatDescriptor): void {
 86Ôćĺ    if (this.formats.has(format.id)) {
 87Ôćĺ      throw new Error(`Format "${format.id}" is already registered.`);
 88Ôćĺ    }
 89Ôćĺ    this.formats.set(format.id, { ...format });
 90Ôćĺ  }
 91Ôćĺ
 92Ôćĺ  get(id: string): OutputFormatDescriptor | undefined {
 93Ôćĺ    const stored = this.formats.get(id);
 94Ôćĺ    return stored ? { ...stored } : undefined;
 95Ôćĺ  }
 96Ôćĺ
 97Ôćĺ  getAll(): OutputFormatDescriptor[] {
 98Ôćĺ    return [...this.formats.values()].map((f) => ({ ...f }));
 99Ôćĺ  }
100Ôćĺ
101Ôćĺ  getAdjustable(): OutputFormatDescriptor[] {
102Ôćĺ    return this.getAll().filter((f) => f.adjustable);
